import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const root = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const entry = "./app.js";
const modules = new Map();

const normalizeId = (id) => {
  const normalized = path.posix.normalize(id.replaceAll(path.sep, "/"));
  return normalized.startsWith(".") ? normalized : `./${normalized}`;
};

const resolveImport = (fromId, request) => {
  const base = path.posix.dirname(fromId);
  return normalizeId(path.posix.join(base, request));
};

const parseNamedImport = (specifier) =>
  specifier
    .split(",")
    .map((part) => part.trim())
    .filter(Boolean)
    .map((part) => {
      const [imported, local] = part.split(/\s+as\s+/);
      return local ? `${imported.trim()}: ${local.trim()}` : imported.trim();
    })
    .join(", ");

const transform = (id, source) => {
  let output = source;

  output = output.replace(/import\s+\{([^}]+)\}\s+from\s+["']([^"']+)["'];/g, (_match, specifier, request) => {
    const depId = resolveImport(id, request);
    return `const { ${parseNamedImport(specifier)} } = __require__("${depId}");`;
  });

  output = output.replace(/import\s+["']([^"']+)["'];/g, (_match, request) => {
    const depId = resolveImport(id, request);
    return `__require__("${depId}");`;
  });

  output = output.replace(/export\s+const\s+([A-Za-z_$][\w$]*)\s*=/g, "const $1 = exports.$1 =");

  return output;
};

const collect = (id) => {
  id = normalizeId(id);
  if (modules.has(id)) return;

  const fullPath = path.join(root, id);
  const source = fs.readFileSync(fullPath, "utf8");
  modules.set(id, source);

  const importPattern = /import(?:\s+\{[^}]+\}\s+from\s+|\s+)["']([^"']+)["'];/g;
  for (const match of source.matchAll(importPattern)) {
    collect(resolveImport(id, match[1]));
  }
};

collect(entry);

const moduleEntries = [...modules.entries()]
  .map(([id, source]) => {
    const body = transform(id, source);
    return `${JSON.stringify(id)}: function(exports, __require__) {\n${body}\n}`;
  })
  .join(",\n");

const bundle = `/* Generated by scripts/build-bundle.mjs. Edit source modules, not this file. */\n(() => {\n  const __modules__ = {\n${moduleEntries}\n  };\n  const __cache__ = {};\n  function __require__(id) {\n    if (__cache__[id]) return __cache__[id].exports;\n    const module = { exports: {} };\n    __cache__[id] = module;\n    __modules__[id](module.exports, __require__);\n    return module.exports;\n  }\n  __require__("./app.js");\n})();\n`;

fs.writeFileSync(path.join(root, "app.bundle.js"), bundle);
